arguments.command:
set -e
# Try to derive public key from the provided private key
ssh-keygen -y -f /workspace/.ssh/ai_agent_key > /tmp/derived_key.pub 2>/tmp/derive_err || true

# Show results
if [ -s /tmp/derived_key.pub ]; then
  echo "Derived public key:";
  cat /tmp/derived_key.pub;
else
  echo "Failed to derive public key from private key:";
  cat /tmp/derive_err;
fi

# Compare with provided public key (ignore trailing comment differences)
if [ -s /tmp/derived_key.pub ]; then
  DERIVED_NO_COMMENT=$(awk '{print $1" "$2}' /tmp/derived_key.pub)
  PROVIDED_NO_COMMENT=$(awk '{print $1" "$2}' /workspace/.ssh/ai_agent_key.pub)
  echo "\nMatch check (type and key material only):";
  if [ "$DERIVED_NO_COMMENT" = "$PROVIDED_NO_COMMENT" ]; then
    echo "MATCH";
  else
    echo "MISMATCH";
    echo "Derived:  $DERIVED_NO_COMMENT";
    echo "Provided: $PROVIDED_NO_COMMENT";
  fi
fi

